import sys
import itertools

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    H = int(data[0])
    W = int(data[1])
    grid = data[2:H+2]

    # Convert each row to a list of integers
    for i in range(H):
        grid[i] = [int(c) for c in grid[i]]

    # For each column, calculate the number of 1s
    col_counts = [0] * W
    for i in range(H):
        for j in range(W):
            col_counts[j] += grid[i][j]

    min_sum = float('inf')

    # Try all possible combinations of flipping columns (since W <= 18, this is feasible)
    for bits in itertools.product([0, 1], repeat=W):
        # Calculate the total sum after flipping columns and optimally flipping rows
        total = 0
        for j in range(W):
            if bits[j]:
                total += H - col_counts[j]
            else:
                total += col_counts[j]

        # For each row, determine if it should be flipped based on current column flips
        for i in range(H):
            row_sum = 0
            for j in range(W):
                if bits[j]:
                    row_sum += 1 - grid[i][j]
                else:
                    row_sum += grid[i][j]
            total += row_sum

        if total < min_sum:
            min_sum = total

    print(min_sum)

if __name__ == "__main__":
    main()
